  ($$iman$$, $$İman Esasları$$, $$Articles of Faith$$, $$🕋$$, $$İslam inancının temel esasları.$$,
   $$Core foundations of Islamic belief.$$, 1, $$https://islamansiklopedisi.org.tr/iman$$, TIMESTAMPTZ '2026-04-23T00:00:00Z'),
  ($$islam$$, $$İslam'ın Şartları$$, $$Pillars of Islam$$, $$☪️$$, $$Müslümanın temel ibadet ve kulluk başlıkları.$$,
   $$Foundational acts of worship and devotion.$$, 2, $$https://islamansiklopedisi.org.tr/islam$$, TIMESTAMPTZ '2026-04-23T00:00:00Z'),
  ($$seerah$$, $$Siyer$$, $$Prophetic Biography$$, $$🌙$$, $$Hz. Muhammed'in (s.a.v.) hayatından güvenilir başlıklar.$$,
   $$Reliable themes from the Prophet Muhammad's life.$$, 3, $$https://islamansiklopedisi.org.tr/muhammed$$, TIMESTAMPTZ '2026-04-23T00:00:00Z'),
  ($$fiqh$$, $$Fıkıh ve İbadet$$, $$Fiqh and Worship$$, $$📘$$, $$Günlük ibadetlerde temel ilmihal bilgileri.$$,
